package com.enterprise.banking.security;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.crypto.*;
import javax.xml.crypto.dom.DOMStructure;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMSignContext;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.*;
import javax.xml.crypto.dsig.spec.C14NMethodParameterSpec;
import javax.xml.crypto.dsig.spec.TransformParameterSpec;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.*;
import java.security.*;
import java.security.cert.X509Certificate;
import java.util.*;
import java.util.logging.Level;
import java.util.logging.Logger;

public class XMLSignatureUtil {
    
    private static final Logger LOGGER = Logger.getLogger(XMLSignatureUtil.class.getName());
    private static final String SIGNATURE_ALGORITHM = "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256";
    private static final String DIGEST_ALGORITHM = "http://www.w3.org/2001/04/xmlenc#sha256";
    private static final String CANONICALIZATION_ALGORITHM = "http://www.w3.org/2001/10/xml-exc-c14n#";
    
    private final KeyStore keyStore;
    private final String keyAlias;
    private final String keyPassword;
    
    public XMLSignatureUtil(KeyStore keyStore, String keyAlias, String keyPassword) {
        this.keyStore = keyStore;
        this.keyAlias = keyAlias;
        this.keyPassword = keyPassword;
    }
    
    public Document signDocument(Document document, String elementToSignId) throws Exception {
        LOGGER.info("Signing XML document, element ID: " + elementToSignId);
        
        XMLSignatureFactory signFactory = XMLSignatureFactory.getInstance("DOM");
        
        // Create Reference
        List<Transform> transforms = new ArrayList<>();
        transforms.add(signFactory.newTransform(Transform.ENVELOPED, (TransformParameterSpec) null));
        transforms.add(signFactory.newTransform(CANONICALIZATION_ALGORITHM, (TransformParameterSpec) null));
        
        String referenceUri = (elementToSignId != null && !elementToSignId.isEmpty()) 
            ? "#" + elementToSignId : "";
        
        Reference reference = signFactory.newReference(
            referenceUri,
            signFactory.newDigestMethod(DIGEST_ALGORITHM, null),
            transforms,
            null,
            null
        );
        
        // Create SignedInfo
        SignedInfo signedInfo = signFactory.newSignedInfo(
            signFactory.newCanonicalizationMethod(CANONICALIZATION_ALGORITHM, (C14NMethodParameterSpec) null),
            signFactory.newSignatureMethod(SIGNATURE_ALGORITHM, null),
            Collections.singletonList(reference)
        );
        
        // Get private key and certificate
        PrivateKey privateKey = (PrivateKey) keyStore.getKey(keyAlias, keyPassword.toCharArray());
        X509Certificate certificate = (X509Certificate) keyStore.getCertificate(keyAlias);
        
        // Create KeyInfo
        KeyInfoFactory keyInfoFactory = signFactory.getKeyInfoFactory();
        X509Data x509Data = keyInfoFactory.newX509Data(Collections.singletonList(certificate));
        KeyInfo keyInfo = keyInfoFactory.newKeyInfo(Collections.singletonList(x509Data));
        
        // Create XMLSignature
        XMLSignature signature = signFactory.newXMLSignature(signedInfo, keyInfo);
        
        // Sign
        DOMSignContext signContext = new DOMSignContext(privateKey, document.getDocumentElement());
        signContext.setDefaultNamespacePrefix("ds");
        signature.sign(signContext);
        
        LOGGER.info("Document signed successfully");
        return document;
    }
    
    public boolean verifySignature(Document document) throws Exception {
        LOGGER.info("Verifying XML signature");
        
        NodeList signatureNodes = document.getElementsByTagNameNS(
            XMLSignature.XMLNS, "Signature");
        
        if (signatureNodes.getLength() == 0) {
            LOGGER.warning("No XML Signature found in document");
            return false;
        }
        
        XMLSignatureFactory signFactory = XMLSignatureFactory.getInstance("DOM");
        
        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElement = (Element) signatureNodes.item(i);
            
            DOMValidateContext validateContext = new DOMValidateContext(
                new X509KeySelector(keyStore), signatureElement);
            
            XMLSignature signature = signFactory.unmarshalXMLSignature(validateContext);
            boolean coreValidity = signature.validate(validateContext);
            
            if (!coreValidity) {
                LOGGER.warning("Signature validation failed for signature #" + i);
                
                // Debug: check individual reference validity
                boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
                LOGGER.info("Signature value validity: " + signatureValueValid);
                
                @SuppressWarnings("unchecked")
                List<Reference> refs = signature.getSignedInfo().getReferences();
                for (Reference ref : refs) {
                    boolean refValid = ref.validate(validateContext);
                    LOGGER.info("Reference [" + ref.getURI() + "] validity: " + refValid);
                }
                
                return false;
            }
        }
        
        LOGGER.info("All signatures verified successfully");
        return true;
    }
    
    public List<String> extractSignedElements(Document document) throws Exception {
        List<String> signedElements = new ArrayList<>();
        
        NodeList signatureNodes = document.getElementsByTagNameNS(
            XMLSignature.XMLNS, "Signature");
        
        XMLSignatureFactory signFactory = XMLSignatureFactory.getInstance("DOM");
        
        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElement = (Element) signatureNodes.item(i);
            
            DOMValidateContext validateContext = new DOMValidateContext(
                new X509KeySelector(keyStore), signatureElement);
            
            XMLSignature signature = signFactory.unmarshalXMLSignature(validateContext);
            
            @SuppressWarnings("unchecked")
            List<Reference> references = signature.getSignedInfo().getReferences();
            
            for (Reference ref : references) {
                String uri = ref.getURI();
                if (uri != null && !uri.isEmpty()) {
                    signedElements.add(uri.startsWith("#") ? uri.substring(1) : uri);
                } else {
                    signedElements.add("ENTIRE_DOCUMENT");
                }
                
                LOGGER.info("Signed element found: " + uri 
                    + " | Digest method: " + ref.getDigestMethod().getAlgorithm());
            }
        }
        
        return signedElements;
    }
    
    public static String documentToString(Document document) throws Exception {
        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        Transformer transformer = transformerFactory.newTransformer();
        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(document), new StreamResult(writer));
        return writer.toString();
    }
    
    public static Document stringToDocument(String xmlString) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        // Prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        return factory.newDocumentBuilder().parse(
            new org.xml.sax.InputSource(new StringReader(xmlString)));
    }
}

