package com.enterprise.banking.security;

import javax.xml.crypto.*;
import javax.xml.crypto.dsig.SignatureMethod;
import javax.xml.crypto.dsig.keyinfo.*;
import java.security.Key;
import java.security.KeyStore;
import java.security.PublicKey;
import java.security.cert.Certificate;
import java.security.cert.X509Certificate;
import java.util.Enumeration;
import java.util.Iterator;
import java.util.List;
import java.util.logging.Logger;

public class X509KeySelector extends KeySelector {
    
    private static final Logger LOGGER = Logger.getLogger(X509KeySelector.class.getName());
    private final KeyStore keyStore;
    
    public X509KeySelector(KeyStore keyStore) {
        this.keyStore = keyStore;
    }
    
    @Override
    @SuppressWarnings("unchecked")
    public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose, 
                                     AlgorithmMethod method, XMLCryptoContext context)
            throws KeySelectorException {
        
        if (keyInfo == null) {
            throw new KeySelectorException("KeyInfo is null");
        }
        
        SignatureMethod signatureMethod = (SignatureMethod) method;
        List<XMLStructure> keyInfoContent = keyInfo.getContent();
        
        for (XMLStructure xmlStructure : keyInfoContent) {
            if (xmlStructure instanceof X509Data) {
                X509Data x509Data = (X509Data) xmlStructure;
                List<?> x509Content = x509Data.getContent();
                
                for (Object content : x509Content) {
                    if (content instanceof X509Certificate) {
                        X509Certificate cert = (X509Certificate) content;
                        PublicKey publicKey = cert.getPublicKey();
                        
                        if (isKeyCompatible(publicKey, signatureMethod.getAlgorithm())) {
                            // Verify the certificate is trusted
                            if (isCertificateTrusted(cert)) {
                                LOGGER.info("Found trusted certificate for: " 
                                    + cert.getSubjectX500Principal().getName());
                                return () -> publicKey;
                            }
                        }
                    }
                }
            }
            
            if (xmlStructure instanceof KeyValue) {
                try {
                    PublicKey publicKey = ((KeyValue) xmlStructure).getPublicKey();
                    if (isKeyCompatible(publicKey, signatureMethod.getAlgorithm())) {
                        return () -> publicKey;
                    }
                } catch (KeyException e) {
                    throw new KeySelectorException("Failed to extract public key", e);
                }
            }
        }
        
        throw new KeySelectorException("No suitable key found in KeyInfo");
    }
    
    private boolean isCertificateTrusted(X509Certificate certificate) {
        try {
            if (keyStore == null) return true; // No trust store configured
            
            Enumeration<String> aliases = keyStore.aliases();
            while (aliases.hasMoreElements()) {
                String alias = aliases.nextElement();
                Certificate trustedCert = keyStore.getCertificate(alias);
                if (trustedCert instanceof X509Certificate) {
                    if (certificate.equals(trustedCert)) {
                        return true;
                    }
                    try {
                        certificate.verify(trustedCert.getPublicKey());
                        return true;
                    } catch (Exception e) {
                        // Not signed by this cert, continue
                    }
                }
            }
            
            LOGGER.warning("Certificate not found in trust store: " 
                + certificate.getSubjectX500Principal().getName());
            return false;
        } catch (Exception e) {
            LOGGER.severe("Error checking certificate trust: " + e.getMessage());
            return false;
        }
    }
    
    private boolean isKeyCompatible(PublicKey key, String algorithm) {
        String keyAlg = key.getAlgorithm();
        if ("RSA".equalsIgnoreCase(keyAlg)) {
            return algorithm.contains("rsa") || algorithm.contains("RSA");
        }
        if ("DSA".equalsIgnoreCase(keyAlg)) {
            return algorithm.contains("dsa") || algorithm.contains("DSA");
        }
        if ("EC".equalsIgnoreCase(keyAlg)) {
            return algorithm.contains("ecdsa") || algorithm.contains("ECDSA");
        }
        return false;
    }
}

