package com.enterprise.banking.security;

import org.apache.wss4j.common.ConfigurationConstants;
import org.apache.wss4j.common.crypto.Crypto;
import org.apache.wss4j.common.crypto.CryptoFactory;
import org.apache.wss4j.common.crypto.Merlin;
import org.apache.wss4j.common.ext.WSSecurityException;

import java.io.FileInputStream;
import java.io.IOException;
import java.security.KeyStore;
import java.security.KeyStoreException;
import java.security.NoSuchAlgorithmException;
import java.security.cert.CertificateException;
import java.util.HashMap;
import java.util.Map;
import java.util.Properties;
import java.util.logging.Logger;

public class WsSecurityConfig {
    
    private static final Logger LOGGER = Logger.getLogger(WsSecurityConfig.class.getName());
    
    private final String keystorePath;
    private final String keystorePassword;
    private final String keyAlias;
    private final String keyPassword;
    private final String truststorePath;
    private final String truststorePassword;
    
    public WsSecurityConfig(String keystorePath, String keystorePassword, 
                            String keyAlias, String keyPassword,
                            String truststorePath, String truststorePassword) {
        this.keystorePath = keystorePath;
        this.keystorePassword = keystorePassword;
        this.keyAlias = keyAlias;
        this.keyPassword = keyPassword;
        this.truststorePath = truststorePath;
        this.truststorePassword = truststorePassword;
    }
    
    public KeyStore loadKeyStore() throws KeyStoreException, IOException, 
            NoSuchAlgorithmException, CertificateException {
        KeyStore ks = KeyStore.getInstance("JKS");
        try (FileInputStream fis = new FileInputStream(keystorePath)) {
            ks.load(fis, keystorePassword.toCharArray());
        }
        LOGGER.info("KeyStore loaded from: " + keystorePath);
        return ks;
    }
    
    public KeyStore loadTrustStore() throws KeyStoreException, IOException, 
            NoSuchAlgorithmException, CertificateException {
        KeyStore ts = KeyStore.getInstance("JKS");
        try (FileInputStream fis = new FileInputStream(truststorePath)) {
            ts.load(fis, truststorePassword.toCharArray());
        }
        LOGGER.info("TrustStore loaded from: " + truststorePath);
        return ts;
    }
    
    public Crypto createCrypto() throws WSSecurityException {
        Properties cryptoProperties = new Properties();
        cryptoProperties.setProperty("org.apache.wss4j.crypto.provider", 
            "org.apache.wss4j.common.crypto.Merlin");
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.keystore.type", "JKS");
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.keystore.file", keystorePath);
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.keystore.password", keystorePassword);
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.keystore.alias", keyAlias);
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.keystore.private.password", keyPassword);
        
        return CryptoFactory.getInstance(cryptoProperties);
    }
    
    public Crypto createTrustCrypto() throws WSSecurityException {
        Properties cryptoProperties = new Properties();
        cryptoProperties.setProperty("org.apache.wss4j.crypto.provider", 
            "org.apache.wss4j.common.crypto.Merlin");
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.truststore.type", "JKS");
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.truststore.file", truststorePath);
        cryptoProperties.setProperty("org.apache.wss4j.crypto.merlin.truststore.password", truststorePassword);
        
        return CryptoFactory.getInstance(cryptoProperties);
    }
    
    public Map<String, Object> getOutboundSecurityProperties() {
        Map<String, Object> outProps = new HashMap<>();
        outProps.put(ConfigurationConstants.ACTION, 
            ConfigurationConstants.SIGNATURE + " " + ConfigurationConstants.TIMESTAMP);
        outProps.put(ConfigurationConstants.USER, keyAlias);
        outProps.put(ConfigurationConstants.SIG_PROP_FILE, "ws-security-sign.properties");
        outProps.put(ConfigurationConstants.SIG_KEY_ID, "DirectReference");
        outProps.put(ConfigurationConstants.SIG_ALGO, 
            "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        outProps.put(ConfigurationConstants.SIG_DIGEST_ALGO, 
            "http://www.w3.org/2001/04/xmlenc#sha256");
        outProps.put(ConfigurationConstants.SIGNATURE_PARTS, 
            "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body;" +
            "{Element}{http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd}Timestamp");
        return outProps;
    }
    
    public Map<String, Object> getInboundSecurityProperties() {
        Map<String, Object> inProps = new HashMap<>();
        inProps.put(ConfigurationConstants.ACTION, 
            ConfigurationConstants.SIGNATURE + " " + ConfigurationConstants.TIMESTAMP);
        inProps.put(ConfigurationConstants.SIG_VER_PROP_FILE, "ws-security-verify.properties");
        return inProps;
    }
    
    public String getKeyAlias() { return keyAlias; }
    public String getKeyPassword() { return keyPassword; }
    public String getKeystorePath() { return keystorePath; }
    public String getKeystorePassword() { return keystorePassword; }
}

// ============================================
// 12. Server Password Callback Handler
// ============================================

package com.enterprise.banking.security;

import org.apache.wss4j.common.ext.WSPasswordCallback;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

public class ServerPasswordCallbackHandler implements CallbackHandler {
    
    private static final Logger LOGGER = Logger.getLogger(ServerPasswordCallbackHandler.class.getName());
    private static final Map<String, String> passwords = new ConcurrentHashMap<>();
    
    static {
        // In production, load from secure vault / HSM
        passwords.put("banking-server", "serverKeystorePassword");
        passwords.put("banking-client", "clientKeystorePassword");
    }
    
    public static void addPassword(String alias, String password) {
        passwords.put(alias, password);
    }
    
    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback wspc = (WSPasswordCallback) callback;
                String identifier = wspc.getIdentifier();
                
                LOGGER.info("Password callback for identifier: " + identifier);
                
                String password = passwords.get(identifier);
                if (password != null) {
                    wspc.setPassword(password);
                } else {
                    LOGGER.warning("No password found for identifier: " + identifier);
                    throw new IOException("No password configured for: " + identifier);
                }
            } else {
                throw new UnsupportedCallbackException(callback, 
                    "Unsupported callback type: " + callback.getClass().getName());
            }
        }
    }
}

// ============================================
// 13. SOAP Message Parser
// ============================================

package com.enterprise.banking.security;

import com.enterprise.banking.model.TransactionRequest;
import com.enterprise.banking.model.TransactionType;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.*;
import java.io.StringReader;
import java.math.BigDecimal;
import java.util.*;
import java.util.logging.Logger;

public class SOAPMessageParser {
    
    private static final Logger LOGGER = Logger.getLogger(SOAPMessageParser.class.getName());
    
    private static final String SOAP_ENV_NS = "http://schemas.xmlsoap.org/soap/envelope/";
    private static final String SOAP_12_ENV_NS = "http://www.w3.org/2003/05/soap-envelope";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String DS_NS = "http://www.w3.org/2000/09/xmldsig#";
    
    public Document parseSOAPMessage(String soapXml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        // Prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setExpandEntityReferences(false);
        
        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new InputSource(new StringReader(soapXml)));
    }
    
    public Element extractSOAPBody(Document soapDocument) {
        // Try SOAP 1.1
        NodeList bodyList = soapDocument.getElementsByTagNameNS(SOAP_ENV_NS, "Body");
        if (bodyList.getLength() > 0) {
            return (Element) bodyList.item(0);
        }
        
        // Try SOAP 1.2
        bodyList = soapDocument.getElementsByTagNameNS(SOAP_12_ENV_NS, "Body");
        if (bodyList.getLength() > 0) {
            return (Element) bodyList.item(0);
        }
        
        LOGGER.warning("No SOAP Body found in document");
        return null;
    }
    
    public Element extractSOAPHeader(Document soapDocument) {
        NodeList headerList = soapDocument.getElementsByTagNameNS(SOAP_ENV_NS, "Header");
        if (headerList.getLength() > 0) {
            return (Element) headerList.item(0);
        }
        
        headerList = soapDocument.getElementsByTagNameNS(SOAP_12_ENV_NS, "Header");
        if (headerList.getLength() > 0) {
            return (Element) headerList.item(0);
        }
        
        return null;
    }
    
    public Element extractSecurityHeader(Document soapDocument) {
        NodeList securityList = soapDocument.getElementsByTagNameNS(WSSE_NS, "Security");
        if (securityList.getLength() > 0) {
            return (Element) securityList.item(0);
        }
        
        LOGGER.warning("No WS-Security header found");
        return null;
    }
    
    public List<SignedElementInfo> extractSignedElements(Document soapDocument) {
        List<SignedElementInfo> signedElements = new ArrayList<>();
        
        NodeList signatureList = soapDocument.getElementsByTagNameNS(DS_NS, "Signature");
        
        for (int i = 0; i < signatureList.getLength(); i++) {
            Element signatureElement = (Element) signatureList.item(i);
            
            NodeList referenceList = signatureElement.getElementsByTagNameNS(DS_NS, "Reference");
            
            for (int j = 0; j < referenceList.getLength(); j++) {
                Element refElement = (Element) referenceList.item(j);
                String uri = refElement.getAttribute("URI");
                
                // Get digest method
                String digestMethod = "";
                NodeList digestMethodNodes = refElement.getElementsByTagNameNS(DS_NS, "DigestMethod");
                if (digestMethodNodes.getLength() > 0) {
                    digestMethod = ((Element) digestMethodNodes.item(0)).getAttribute("Algorithm");
                }
                
                // Get digest value
                String digestValue = "";
                NodeList digestValueNodes = refElement.getElementsByTagNameNS(DS_NS, "DigestValue");
                if (digestValueNodes.getLength() > 0) {
                    digestValue = digestValueNodes.item(0).getTextContent();
                }
                
                // Get transforms
                List<String> transforms = new ArrayList<>();
                NodeList transformList = refElement.getElementsByTagNameNS(DS_NS, "Transform");
                for (int k = 0; k < transformList.getLength(); k++) {
                    transforms.add(((Element) transformList.item(k)).getAttribute("Algorithm"));
                }
                
                // Resolve the referenced element
                Element referencedElement = null;
                if (uri != null && uri.startsWith("#")) {
                    String id = uri.substring(1);
                    referencedElement = findElementById(soapDocument, id);
                }
                
                SignedElementInfo info = new SignedElementInfo(
                    uri, digestMethod, digestValue, transforms, referencedElement
                );
                signedElements.add(info);
                
                LOGGER.info("Found signed element - URI: " + uri 
                    + ", Digest: " + digestMethod);
            }
        }
        
        return signedElements;
    }
    
    private Element findElementById(Document document, String id) {
        // Search with wsu:Id attribute
        NodeList allElements = document.getElementsByTagName("*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element element = (Element) allElements.item(i);
            
            if (id.equals(element.getAttributeNS(WSU_NS, "Id")) 
                || id.equals(element.getAttribute("Id"))
                || id.equals(element.getAttribute("wsu:Id"))) {
                return element;
            }
        }
        
        // Fallback to standard getElementById
        return document.getElementById(id);
    }
    
    public TransactionRequest extractTransactionFromBody(Element soapBody) {
        TransactionRequest request = new TransactionRequest();
        
        Element transactionElement = getFirstChildElement(soapBody);
        if (transactionElement == null) return null;
        
        request.setTransactionId(getElementTextContent(transactionElement, "transactionId"));
        request.setSourceAccountId(getElementTextContent(transactionElement, "sourceAccountId"));
        request.setTargetAccountId(getElementTextContent(transactionElement, "targetAccountId"));
        
        String amountStr = getElementTextContent(transactionElement, "amount");
        if (amountStr != null && !amountStr.isEmpty()) {
            request.setAmount(new BigDecimal(amountStr));
        }
        
        request.setCurrency(getElementTextContent(transactionElement, "currency"));
        
        String typeStr = getElementTextContent(transactionElement, "transactionType");
        if (typeStr != null && !typeStr.isEmpty()) {
            try {
                request.setTransactionType(TransactionType.valueOf(typeStr));
            } catch (IllegalArgumentException e) {
                LOGGER.warning("Unknown transaction type: " + typeStr);
            }
        }
        
        request.setDescription(getElementTextContent(transactionElement, "description"));
        request.setTimestamp(getElementTextContent(transactionElement, "timestamp"));
        
        return request;
    }
    
    public Map<String, String> extractTimestampInfo(Document soapDocument) {
        Map<String, String> timestampInfo = new HashMap<>();
        
        NodeList timestampList = soapDocument.getElementsByTagNameNS(WSU_NS, "Timestamp");
        if (timestampList.getLength() > 0) {
            Element timestampElement = (Element) timestampList.item(0);
            
            NodeList createdList = timestampElement.getElementsByTagNameNS(WSU_NS, "Created");
            if (createdList.getLength() > 0) {
                timestampInfo.put("Created", createdList.item(0).getTextContent());
            }
            
            NodeList expiresList = timestampElement.getElementsByTagNameNS(WSU_NS, "Expires");
            if (expiresList.getLength() > 0) {
                timestampInfo.put("Expires", expiresList.item(0).getTextContent());
            }
            
            String id = timestampElement.getAttributeNS(WSU_NS, "Id");
            if (!id.isEmpty()) {
                timestampInfo.put("Id", id);
            }
        }
        
        return timestampInfo;
    }
    
    public Map<String, String> extractUsernameTokenInfo(Document soapDocument) {
        Map<String, String> tokenInfo = new HashMap<>();
        
        NodeList tokenList = soapDocument.getElementsByTagNameNS(WSSE_NS, "UsernameToken");
        if (tokenList.getLength() > 0) {
            Element tokenElement = (Element) tokenList.item(0);
            
            NodeList usernameList = tokenElement.getElementsByTagNameNS(WSSE_NS, "Username");
            if (usernameList.getLength() > 0) {
                tokenInfo.put("Username", usernameList.item(0).getTextContent());
            }
            
            NodeList nonceList = tokenElement.getElementsByTagNameNS(WSSE_NS, "Nonce");
            if (nonceList.getLength() > 0) {
                tokenInfo.put("Nonce", nonceList.item(0).getTextContent());
            }
        }
        
        return tokenInfo;
    }
    
    private Element getFirstChildElement(Element parent) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i) instanceof Element) {
                return (Element) children.item(i);
            }
        }
        return null;
    }
    
    private String getElementTextContent(Element parent, String localName) {
        NodeList nodes = parent.getElementsByTagName(localName);
        if (nodes.getLength() == 0) {
            // Try with namespace
            nodes = parent.getElementsByTagNameNS("*", localName);
        }
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent();
        }
        return null;
    }
    
    // Inner class for signed element metadata
    public static class SignedElementInfo {
        private final String uri;
        private final String digestMethod;
        private final String digestValue;
        private final List<String> transforms;
        private final Element referencedElement;
        
        public SignedElementInfo(String uri, String digestMethod, String digestValue,
                                 List<String> transforms, Element referencedElement) {
            this.uri = uri;
            this.digestMethod = digestMethod;
            this.digestValue = digestValue;
            this.transforms = transforms;
            this.referencedElement = referencedElement;
        }
        
        public String getUri() { return uri; }
        public String getDigestMethod() { return digestMethod; }
        public String getDigestValue() { return digestValue; }
        public List<String> getTransforms() { return transforms; }
        public Element getReferencedElement() { return referencedElement; }
        
        @Override
        public String toString() {
            return "SignedElementInfo{uri='" + uri + "', digestMethod='" + digestMethod 
                + "', transforms=" + transforms + "}";
        }
    }
}

// ============================================
// 14. WS-Security Interceptor (CXF-based)
// ============================================

package com.enterprise.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.apache.wss4j.common.ext.WSSecurityException;
import org.apache.wss4j.dom.WSConstants;
import org.apache.wss4j.dom.engine.WSSecurityEngine;
import org.apache.wss4j.dom.engine.WSSecurityEngineResult;
import org.apache.wss4j.dom.handler.WSHandlerResult;
import org.w3c.dom.Document;

import javax.xml.namespace.QName;
import java.util.*;
import java.util.logging.Level;
import java.util.logging.Logger;

public class BankingSecurityInterceptor extends AbstractSoapInterceptor {
    
    private static final Logger LOGGER = Logger.getLogger(BankingSecurityInterceptor.class.getName());
    private static final Set<QName> UNDERSTOOD_HEADERS = new HashSet<>();
    
    private final WsSecurityConfig securityConfig;
    private final SOAPMessageParser soapParser;
    
    static {
        UNDERSTOOD_HEADERS.add(new QName(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd",
            "Security"));
    }
    
    public BankingSecurityInterceptor(WsSecurityConfig securityConfig) {
        super(Phase.PRE_PROTOCOL);
        this.securityConfig = securityConfig;
        this.soapParser = new SOAPMessageParser();
    }
    
    @Override
    public Set<QName> getUnderstoodHeaders() {
        return UNDERSTOOD_HEADERS;
    }
    
    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        LOGGER.info("Processing incoming SOAP message for security verification");
        
        try {
            Document soapDocument = message.getContent(Document.class);
            
            if (soapDocument == null) {
                LOGGER.warning("No SOAP document found in message");
                throw new Fault(new SecurityException("Missing SOAP document"));
            }
            
            // Extract and log security information
            logSecurityInfo(soapDocument);
            
            // Verify WS-Security elements
            verifySecurityElements(soapDocument, message);
            
            LOGGER.info("Security verification completed successfully");
            
        } catch (Fault f) {
            throw f;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Security verification failed", e);
            throw new Fault(new SecurityException("WS-Security verification failed: " 
                + e.getMessage(), e));
        }
    }
    
    private void logSecurityInfo(Document soapDocument) {
        // Extract timestamp info
        Map<String, String> timestampInfo = soapParser.extractTimestampInfo(soapDocument);
        if (!timestampInfo.isEmpty()) {
            LOGGER.info("Timestamp - Created: " + timestampInfo.get("Created") 
                + ", Expires: " + timestampInfo.get("Expires"));
        }
        
        // Extract signed elements
        List<SOAPMessageParser.SignedElementInfo> signedElements = 
            soapParser.extractSignedElements(soapDocument);
        for (SOAPMessageParser.SignedElementInfo info : signedElements) {
            LOGGER.info("Signed element: " + info);
        }
        
        // Extract username token if present
        Map<String, String> tokenInfo = soapParser.extractUsernameTokenInfo(soapDocument);
        if (tokenInfo.containsKey("Username")) {
            LOGGER.info("UsernameToken found for user: " + tokenInfo.get("Username"));
        }
    }
    
    private void verifySecurityElements(Document soapDocument, SoapMessage message) 
            throws Exception {
        
        WSSecurityEngine securityEngine = new WSSecurityEngine();
        
        org.apache.wss4j.dom.handler.RequestData requestData = 
            new org.apache.wss4j.dom.handler.RequestData();
        requestData.setSigVerCrypto(securityConfig.createTrustCrypto());
        requestData.setDecCrypto(securityConfig.createCrypto());
        requestData.setCallbackHandler(new ServerPasswordCallbackHandler());
        
        try {
            WSHandlerResult results = securityEngine.processSecurityHeader(
                soapDocument, requestData);
            
            if (results != null) {
                List<WSSecurityEngineResult> securityResults = results.getResults();
                
                for (WSSecurityEngineResult result : securityResults) {
                    Integer action = (Integer) result.get(WSSecurityEngineResult.TAG_ACTION);
                    
                    if (action != null) {
                        switch (action) {
                            case WSConstants.SIGN:
                                LOGGER.info("Signature verified successfully");
                                break;
                            case WSConstants.TS:
                                LOGGER.info("Timestamp validated");
                                break;
                            case WSConstants.UT:
                                LOGGER.info("UsernameToken validated");
                                break;
                            case WSConstants.ENCR:
                                LOGGER.info("Encryption processed");
                                break;
                            default:
                                LOGGER.info("WS-Security action processed: " + action);
                        }
                    }
                }
                
                // Store results in message context for downstream processing
                message.put("ws-security.results", results);
            }
        } catch (WSSecurityException e) {
            LOGGER.severe("WS-Security processing failed: " + e.getMessage());
            throw e;
        }
    }
}

