// 15. Audit Logger
// ============================================

package com.enterprise.banking.security;

import com.enterprise.banking.model.TransactionRequest;
import com.enterprise.banking.model.TransactionResponse;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.logging.Logger;

public class AuditLogger {
    
    private static final Logger LOGGER = Logger.getLogger("BANKING_AUDIT");
    private static final DateTimeFormatter FORMATTER = 
        DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss.SSS");
    
    public static void logTransactionRequest(TransactionRequest request, 
                                              boolean signatureValid, String clientId) {
        StringBuilder sb = new StringBuilder();
        sb.append("[TRANSACTION_REQUEST] ");
        sb.append("Time=").append(LocalDateTime.now().format(FORMATTER));
        sb.append(" | TxnId=").append(request.getTransactionId());
        sb.append(" | Type=").append(request.getTransactionType());
        sb.append(" | From=").append(maskAccountId(request.getSourceAccountId()));
        sb.append(" | To=").append(maskAccountId(request.getTargetAccountId()));
        sb.append(" | Amount=").append(request.getAmount()).append(" ").append(request.getCurrency());
        sb.append(" | SignatureValid=").append(signatureValid);
        sb.append(" | ClientId=").append(clientId);
        
        LOGGER.info(sb.toString());
    }
    
    public static void logTransactionResponse(TransactionResponse response) {
        StringBuilder sb = new StringBuilder();
        sb.append("[TRANSACTION_RESPONSE] ");
        sb.append("Time=").append(LocalDateTime.now().format(FORMATTER));
        sb.append(" | TxnId=").append(response.getTransactionId());
        sb.append(" | Status=").append(response.getStatus());
        sb.append(" | Confirmation=").append(response.getConfirmationNumber());
        
        LOGGER.info(sb.toString());
    }
    
    public static void logSecurityEvent(String eventType, String details) {
        StringBuilder sb = new StringBuilder();
        sb.append("[SECURITY_EVENT] ");
        sb.append("Time=").append(LocalDateTime.now().format(FORMATTER));
        sb.append(" | Event=").append(eventType);
        sb.append(" | Details=").append(details);
        
        LOGGER.info(sb.toString());
    }
    
    private static String maskAccountId(String accountId) {
        if (accountId == null || accountId.length() < 4) return "****";
        return "****" + accountId.substring(accountId.length() - 4);
    }
}

